const body = $input.first().json.body;
if (!body.description_lao) throw new Error('ຕ້ອງມີຄຳອະທິບາຍ');
const type = body.type || 'product';
const styles = {
  product: 'professional product photo, clean background, high quality, commercial photography',
  banner: 'marketing banner design, bold typography space, modern design, brand colors',
  social: 'social media post, lifestyle photography, vibrant colors, engaging composition'
};
return [{ json: {
  description_lao: body.description_lao,
  brand: body.brand || 'PHANUKNGAN',
  type,
  platforms: body.platforms || ['facebook', 'tiktok'],
  schedule_time: body.schedule_time || null,
  mj_prompt: `${body.description_lao_en || 'product'}, ${styles[type]}, --ar 1:1 --q 2 --style raw`,
  job_id: body.job_id || 'job_' + Date.now()
}}];

const translateResp = $input.first().json;
const translated = translateResp.content[0].text.trim();
const styles = { product: '--ar 1:1 --q 2', banner: '--ar 16:9 --q 2', social: '--ar 4:5 --q 2' };
const prevData = $('ກວດ + ກຽມ Prompt').first().json;
return [{ json: { ...prevData, mj_prompt_final: `${translated}, professional commercial photography, high quality product shot, clean studio background, ${styles[prevData.type] || '--ar 1:1 --q 2'} --style raw` } }];

