const captionResp = $input.first().json;
const caption = captionResp.content[0].text.trim();
const prev = $('ກວດ + ກຽມ Prompt').first().json;
const canvaResp = $('Canva ໃສ່ Logo + ຂໍ້ຄວາມລາວ').first().json;
return [{ json: { ...prev, caption, image_url: canvaResp.urls?.view || canvaResp.thumbnail_url || 'pending', canva_design_id: canvaResp.id } }];
